// ─────────────────────────────────────────────────────────────────────────────
//  api.js  —  ShowSpot
//  Spring Boot wraps everything as: { data: T, message: string, success: bool }
//  Axios wraps HTTP response as:    res.data  (= the Spring Boot body above)
//  So in pages:  res.data.data  = the actual payload  ✓
// ─────────────────────────────────────────────────────────────────────────────

import axios from 'axios';

const api = axios.create({
  baseURL: 'http://localhost:8080/api',
  headers: { 'Content-Type': 'application/json' },
});

// attach JWT to every request
api.interceptors.request.use((cfg) => {
  const token = localStorage.getItem('token');
  if (token) cfg.headers.Authorization = `Bearer ${token}`;
  return cfg;
});

// on 401 → wipe session and redirect to login
api.interceptors.response.use(
  (res) => res,
  (err) => {
    if (err.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }
    return Promise.reject(err);
  }
);

export default api;

// ─── AUTH ────────────────────────────────────────────────────────────────────
// POST /api/auth/login      body: { mail, password }
// POST /api/auth/register   body: { name, mail, contactNo, password, role }
// GET  /api/auth/check-email?email=
export const loginUser        = (data)  => api.post('/users/login', data);
export const registerUser     = (data)  => api.post('/auth/register', data);
export const checkEmailExists = (email) =>
  api.get(`/auth/check-email?email=${encodeURIComponent(email)}`).catch(() => ({
    data: { data: { exists: false } },
  }));

// ─── EVENTS ──────────────────────────────────────────────────────────────────
export const getAllEvents          = (sortBy)      => api.get('/events', { params: sortBy ? { sortBy } : {} });
export const filterEvents         = (params)       => api.get('/events/filter', { params });
export const getEventById         = (id)           => api.get(`/events/${id}`);
export const getEventsByOrganiser = (organiserId)  => api.get(`/events/organiser/${organiserId}`);
export const searchEvents         = (name)         => api.get('/events/search', { params: { name } });
export const createEvent          = (data)         => api.post('/events', data);
export const updateEvent          = (id, data)     => api.put(`/events/${id}`, data);
export const deleteEvent          = (id)           => api.delete(`/events/${id}`);

// ─── SHOW SLOTS ───────────────────────────────────────────────────────────────
export const getSlotsByEvent = (eventId)   => api.get(`/show-slots/event/${eventId}`);
export const getSlotById     = (id)        => api.get(`/show-slots/${id}`);
export const createSlot      = (data)      => api.post('/show-slots', data);
export const updateSlot      = (id, data)  => api.put(`/show-slots/${id}`, data);
export const deleteSlot      = (id)        => api.delete(`/show-slots/${id}`);

// ─── LOCATIONS ───────────────────────────────────────────────────────────────
export const getAllLocations = ()        => api.get('/locations');
export const getLocationById = (id)     => api.get(`/locations/${id}`);
export const createLocation  = (data)   => api.post('/locations', data);
export const deleteLocation  = (id)     => api.delete(`/locations/${id}`);

// ─── SEATS ───────────────────────────────────────────────────────────────────
// getSeatsByLocation  → seats configured at a venue
// getAvailableSeats   → seat-slots for a specific show slot (for booking)
export const getSeatsByLocation = (locationId)     => api.get(`/seats/location/${locationId}`);
export const getAvailableSeats  = (slotId)         => api.get(`/seat-slots/slot/${slotId}`);
export const createSeat         = (locationId, data) =>
  api.post('/seats', data, { params: { locationId } });
export const updateSeat         = (id, data)       => api.put(`/seats/${id}`, data);
export const deleteSeat         = (id)             => api.delete(`/seats/${id}`);

// ─── RESERVATIONS ─────────────────────────────────────────────────────────────
export const bookSeats                  = (data)    => api.post('/reservations', data);
export const getReservationsByUser      = (userId)  => api.get(`/reservations/user/${userId}`);
export const getReservationsByOrganiser = (orgId)   => api.get(`/reservations/organiser/${orgId}`);
export const cancelReservation          = (data)    =>
  api.post(`/reservations/${data.reservationId}/cancel`, {
    userId: data.userId,
    reason: data.reason,
  });

// ─── TRANSACTIONS ─────────────────────────────────────────────────────────────
export const processPayment             = (data)   => api.post('/transactions', data);
export const getTransactionsByOrganiser = (orgId)  => api.get(`/transactions/organiser/${orgId}`);
export const getTransactionsByUser      = (userId) => api.get(`/transactions/user/${userId}`);

// ─── CANCELLATIONS ────────────────────────────────────────────────────────────
export const getAllCancellations         = ()            => api.get('/cancellations');
export const getCancellationsByOrganiser = (orgId)      => api.get(`/cancellations/organiser/${orgId}`);
export const updateRefundStatus          = (id, status) =>
  api.put(`/cancellations/${id}/refund`, { refundStatus: status });

// ─── NOTIFICATIONS ────────────────────────────────────────────────────────────
export const getNotificationsByUser = (userId) => api.get(`/notifications/user/${userId}`);
export const markNotificationRead   = (id)     => api.put(`/notifications/${id}/read`);
export const sendBulkNotification   = (data)   => api.post('/notifications/send-bulk', data);
export const sendSlotReminders      = (slotId) => api.post(`/notifications/remind/${slotId}`);
